// ============================================================================
// EXTRACT SESSION ID NODE V10 - WITH VIEWER IDENTITY PARAMS
// ============================================================================

const query = $input.first().json.query || {};
const headers = $input.first().json.headers || {};

// Extract session identification
const sessionId = query.session_id || '';
const providerId = query.provider_id || '';

// Extract viewer identity for role detection (NEW)
const viewerEmail = (query.user_email || headers['x-user-email'] || '').toLowerCase().trim();
const viewerUserId = query.user_id || headers['x-user-id'] || '';
const viewerRoleHint = query.viewer_role || '';  // Hint from frontend, not authoritative

console.log('=== EXTRACT SESSION ID V10 ===');
console.log('Session ID:', sessionId);
console.log('Provider ID:', providerId);
console.log('Viewer Email:', viewerEmail);
console.log('Viewer User ID:', viewerUserId);
console.log('Viewer Role Hint:', viewerRoleHint);

// Validation
if (!sessionId) {
    throw new Error('Missing required parameter: session_id');
}

return [{
    json: {
        sessionId,
        providerId,
        viewerEmail,
        viewerUserId,
        viewerRoleHint
    }
}];

// ============================================================================
// BUILD CONTRACT STUDIO RESPONSE V10 - WITH VIEWER ROLE DETECTION
// ============================================================================

const sessionId = $("Extract Session ID").first().json.sessionId;
const sessionData = $("Fetch Session").first().json || {};

// ============================================================================
// NEW: GET VIEWER CONTEXT FROM EXTRACT SESSION ID NODE
// ============================================================================

// Get viewer info extracted from webhook query params
const extractedData = $("Extract Session ID").first().json || {};
const viewerEmail = (extractedData.viewerEmail || "").toLowerCase().trim();
const viewerUserId = extractedData.viewerUserId || "";
const viewerRoleHint = extractedData.viewerRoleHint || "";

console.log("=== VIEWER DETECTION ===");
console.log("Viewer email from request:", viewerEmail);
console.log("Viewer user_id from request:", viewerUserId);

console.log("=== SESSION DATA RAW ===");
console.log("sessionData:", JSON.stringify(sessionData));
console.log("sessionData.session_id:", sessionData.session_id);
console.log("sessionData.template_name:", sessionData.template_name);
console.log("sessionData.mediation_type:", sessionData.mediation_type);
console.log("sessionData.template_source:", sessionData.template_source);
console.log("sessionData.clause_count:", sessionData.clause_count);

const leverageData = $("Fetch Leverage Calculation").first().json || {};
const clausePositions = $("Fetch Clause Positions")
  .all()
  .map((item) => item.json);

// Fetch unseen moves data
const unseenMovesData =
  $("Fetch Unseen Moves")
    .all()
    .map((item) => item.json) || [];

// ============================================================================
// NEW: FETCH PROVIDER BIDS FOR VIEWER ROLE DETECTION
// ============================================================================

// Get provider bids data (should already be fetched or fetch now)
let providerBidsData = [];
try {
  providerBidsData =
    $("Fetch Provider Bids")
      .all()
      .map((item) => item.json) || [];
} catch (e) {
  console.log("No Fetch Provider Bids node, using empty array");
}

console.log("=== BUILDING RESPONSE V10 (With Viewer Role Detection) ===");
console.log("Session:", sessionData.session_number);
console.log("Template:", sessionData.template_name);
console.log("Mediation Type:", sessionData.mediation_type);
console.log("Template Source:", sessionData.template_source);
console.log("Clause positions from DB:", clausePositions.length);
console.log("Provider bids count:", providerBidsData.length);

// ============================================================================
// SECTION 1: PARSE LEVERAGE FACTORS
// ============================================================================

let leverageFactors = {};
try {
  const breakdown = leverageData.leverage_factors_breakdown;
  const factors = leverageData.calculation_factors;

  let factorsSource = null;
  if (
    breakdown &&
    Object.keys(
      typeof breakdown === "string" ? JSON.parse(breakdown) : breakdown,
    ).length > 0
  ) {
    factorsSource = breakdown;
  } else if (
    factors &&
    Object.keys(typeof factors === "string" ? JSON.parse(factors) : factors)
      .length > 0
  ) {
    factorsSource = factors;
  }

  if (factorsSource) {
    leverageFactors =
      typeof factorsSource === "string"
        ? JSON.parse(factorsSource)
        : factorsSource;
  }
  console.log("Parsed leverage factors:", JSON.stringify(leverageFactors));
} catch (e) {
  console.log("Could not parse leverage factors:", e.message);
}

// ============================================================================
// SECTION 2: LEVERAGE VALUES - BASELINE VS TRACKER
// ============================================================================

// BASELINE leverage (from onboarding assessment - NEVER CHANGES)
const baselineCustomerLeverage =
  leverageData.baseline_customer || sessionData.customer_leverage || 50;
const baselineProviderLeverage =
  leverageData.baseline_provider || sessionData.provider_leverage || 50;

// TRACKER leverage (dynamic - changes with position moves)
const trackerCustomerLeverage =
  leverageData.tracker_customer ||
  sessionData.leverage_tracker_customer ||
  baselineCustomerLeverage;
const trackerProviderLeverage =
  leverageData.tracker_provider ||
  sessionData.leverage_tracker_provider ||
  baselineProviderLeverage;

console.log(
  "Baseline leverage:",
  baselineCustomerLeverage,
  "/",
  baselineProviderLeverage,
);
console.log(
  "Tracker leverage:",
  trackerCustomerLeverage,
  "/",
  trackerProviderLeverage,
);

// Check if leverage has been calculated
const hasLeverageCalculation = !!(
  baselineCustomerLeverage && baselineProviderLeverage
);
const hasClausePositions = clausePositions.length > 0;

const alignmentPercentage = leverageData.alignment_percentage || 0;
const isAligned = leverageData.is_aligned || false;

console.log("Has leverage calculation:", hasLeverageCalculation);
console.log("Has clause positions:", hasClausePositions);

// ============================================================================
// SECTION 2A: DETERMINE VIEWER ROLE (NEW)
// ============================================================================

let viewerRole = "unknown";
let viewerBidId = null;
let viewerProviderId = null;
let viewerCompany = null;

// Get customer email from session data
const customerEmail = (
  sessionData.customer_contact_email ||
  sessionData.customer_email ||
  ""
)
  .toLowerCase()
  .trim();

// Get customer created_by
const customerCreatedBy = sessionData.created_by || "";

console.log("=== ROLE DETECTION ===");
console.log("Customer email from session:", customerEmail);
console.log("Session created_by:", customerCreatedBy);
console.log("Viewer email:", viewerEmail);
console.log("Viewer user_id:", viewerUserId);

// Priority 1: Check if viewer is the customer (by email or created_by)
if (viewerEmail && customerEmail && viewerEmail === customerEmail) {
  viewerRole = "customer";
  viewerCompany = sessionData.customer_company || sessionData.customer_name;
  console.log("Role determined: CUSTOMER (email match)");
} else if (
  viewerUserId &&
  customerCreatedBy &&
  viewerUserId === customerCreatedBy
) {
  viewerRole = "customer";
  viewerCompany = sessionData.customer_company || sessionData.customer_name;
  console.log("Role determined: CUSTOMER (created_by match)");
}

// Priority 2: Check if viewer is a provider (check all bids)
if (viewerRole === "unknown" && viewerEmail) {
  for (const bid of providerBidsData) {
    const bidEmail = (bid.provider_contact_email || "").toLowerCase().trim();
    if (bidEmail && viewerEmail === bidEmail) {
      viewerRole = "provider";
      viewerBidId = bid.bid_id;
      viewerProviderId = bid.provider_id;
      viewerCompany = bid.provider_company;
      console.log("Role determined: PROVIDER (email match in bids)");
      console.log("Provider bid_id:", viewerBidId);
      console.log("Provider provider_id:", viewerProviderId);
      break;
    }
  }
}

// Priority 3: Check main provider fields on session (for single-provider sessions)
if (viewerRole === "unknown" && viewerEmail) {
  const mainProviderEmail = (sessionData.provider_contact_email || "")
    .toLowerCase()
    .trim();
  if (mainProviderEmail && viewerEmail === mainProviderEmail) {
    viewerRole = "provider";
    viewerProviderId = sessionData.provider_id;
    viewerBidId = sessionData.bid_id;
    viewerCompany = sessionData.provider_company;
    console.log("Role determined: PROVIDER (main session provider match)");
  }
}

// Priority 4: If viewer_role was passed in query params, use it as hint
// (but only if we couldn't determine from email)
if (viewerRole === "unknown") {
  const hintRole = viewerRoleHint;
  if (hintRole === "customer" || hintRole === "provider") {
    viewerRole = hintRole;
    console.log(
      "Role determined: " +
        viewerRole.toUpperCase() +
        " (from query param hint)",
    );
  }
}

// Final fallback: If still unknown and no provider is set, assume customer
if (viewerRole === "unknown") {
  // If there's no provider yet, user is likely the customer
  if (!sessionData.provider_id && !sessionData.provider_company) {
    viewerRole = "customer";
    viewerCompany = sessionData.customer_company || sessionData.customer_name;
    console.log("Role determined: CUSTOMER (fallback - no provider set)");
  } else {
    // Can't determine - leave as unknown
    console.log("Role could not be determined - leaving as unknown");
  }
}

console.log("=== FINAL VIEWER CONTEXT ===");
console.log("viewerRole:", viewerRole);
console.log("viewerBidId:", viewerBidId);
console.log("viewerProviderId:", viewerProviderId);
console.log("viewerCompany:", viewerCompany);

// ============================================================================
// SECTION 3: BUILD SESSION RESPONSE
// ============================================================================

const session = {
  sessionId: sessionData.session_id || sessionId,
  sessionNumber: sessionData.session_number || "Unknown",
  customerCompany:
    sessionData.customer_company ||
    sessionData.customer_name ||
    "Unknown Customer",
  providerCompany: sessionData.provider_company || "Awaiting Provider",
  providerId: sessionData.provider_id || null,
  bidId: sessionData.bid_id || null,
  customerContactName: sessionData.customer_contact || null,
  providerContactName: sessionData.provider_contact || null,
  customerContactEmail: sessionData.customer_contact_email || null, // NEW
  providerContactEmail: sessionData.provider_contact_email || null, // NEW
  contractType: sessionData.contract_type || "General",
  dealValue: sessionData.deal_value || "0",
  phase: sessionData.phase || "pending",
  status: sessionData.status || "draft",
  industry: sessionData.industry || "General",
  currency: sessionData.currency || "GBP",
  createdAt: sessionData.created_at || null,
  hasClausePositions: hasClausePositions,
  hasLeverageCalculation: hasLeverageCalculation,
  isReadyForNegotiation: hasLeverageCalculation && hasClausePositions,

  // ========== STRAIGHT TO CONTRACT SUPPORT ==========
  mediationType: sessionData.mediation_type || null,
  templateSource: sessionData.template_source || null,
  serviceCriticality: sessionData.service_criticality || null,

  // ========== Template & Clause Builder Tracking ==========
  templateName: sessionData.template_name || null,
  templatePackId: sessionData.template_pack_id || null,
  clausesSelected: sessionData.clauses_selected || false,
  clauseCount: sessionData.clause_count || 0,

  // ========== Training Mode ==========
  isTraining: sessionData.is_training || false,
  notes: sessionData.notes || null,

  // ========== Role Matrix ==========
  contractTypeKey: sessionData.contract_type_key || null,
  initiatorPartyRole: sessionData.initiator_party_role || null,

  // ========== VIEWER CONTEXT (NEW V10) ==========
  viewer: {
    role: viewerRole,
    bidId: viewerBidId,
    providerId: viewerProviderId,
    company: viewerCompany,
    email: viewerEmail || null,
    userId: viewerUserId || null,
  },
};

console.log("Session object built:", {
  mediationType: session.mediationType,
  templateSource: session.templateSource,
  templateName: session.templateName,
  clauseCount: session.clauseCount,
  status: session.status,
  viewer: session.viewer,
});

// ============================================================================
// SECTION 4: CLAUSE MAPPING WITH FULL FIELD SUPPORT
// ============================================================================

// Helper function to safely parse position_options
const parsePositionOptions = (options) => {
  if (!options) return null;
  try {
    return typeof options === "string" ? JSON.parse(options) : options;
  } catch (e) {
    console.log("Could not parse position_options:", e.message);
    return null;
  }
};

// Debug: Log first clause raw data to verify field availability
if (clausePositions.length > 0) {
  console.log("=== FIRST CLAUSE RAW DATA ===");
  console.log("position_id:", clausePositions[0].position_id);
  console.log("clause_id:", clausePositions[0].clause_id);
  console.log("clause_name:", clausePositions[0].clause_name);
  console.log("clause_number:", clausePositions[0].clause_number);
  console.log("category:", clausePositions[0].category);
}

// Build clauses response with camelCase keys
const clauses = clausePositions.map((cp) => ({
  // Core identification
  positionId: cp.position_id || null,
  clauseId: cp.clause_id || null,
  clauseNumber: cp.clause_number || "",
  clauseName: cp.clause_name || "Unnamed Clause",
  category: cp.category || "General",
  description: cp.description || "",

  // Hierarchy
  parentPositionId: cp.parent_position_id || null,
  clauseLevel: cp.clause_level || 1,
  displayOrder: cp.display_order || 0,
  isCategoryHeader: cp.is_category_header || false,

  // Positions (rounded to 1 decimal)
  customerPosition:
    cp.customer_position != null
      ? Math.round(parseFloat(cp.customer_position) * 10) / 10
      : null,
  providerPosition:
    cp.provider_position != null
      ? Math.round(parseFloat(cp.provider_position) * 10) / 10
      : null,
  originalCustomerPosition:
    cp.original_customer_position != null
      ? Math.round(parseFloat(cp.original_customer_position) * 10) / 10
      : null,
  originalProviderPosition:
    cp.original_provider_position != null
      ? Math.round(parseFloat(cp.original_provider_position) * 10) / 10
      : null,
  currentCompromise: cp.current_compromise
    ? Math.round(parseFloat(cp.current_compromise) * 10) / 10
    : null,
  aiSuggestedCompromise:
    cp.ai_suggested_compromise != null
      ? Math.round(parseFloat(cp.ai_suggested_compromise) * 10) / 10
      : null,

  // Gap analysis
  gapSize:
    cp.gap_size != null ? Math.round(parseFloat(cp.gap_size) * 10) / 10 : 0,
  gapSeverity: cp.gap_severity || "low",

  // Weighting
  customerWeight: cp.customer_weight || 5,
  providerWeight: cp.provider_weight || 5,
  isDealBreakerCustomer: cp.is_deal_breaker_customer || false,
  isDealBreakerProvider: cp.is_deal_breaker_provider || false,

  // Content
  clauseContent: cp.clause_content || null,
  customerNotes: cp.customer_notes || null,
  providerNotes: cp.provider_notes || null,
  priorityLevel: cp.priority_level || 5,
  status: cp.status || "pending",
  positionSetAt: cp.position_set_at || null,
  positionSetBy: cp.position_set_by || null,

  // UI State
  isExpanded: true,

  // ========== Clause Management System Fields ==========
  sourceType: cp.source_type || "legacy",
  sourceMasterClauseId: cp.source_master_clause_id || null,
  sourceTemplateClauseId: cp.source_template_clause_id || null,
  addedMidSession: cp.added_mid_session || false,
  addedByParty: cp.added_by_party || null,
  positionOptions: parsePositionOptions(cp.position_options),
  aiContext: cp.ai_context || cp.custom_ai_context || null,
  negotiationGuidance: cp.negotiation_guidance || null,

  // ========== Clause Confirmation Tracking ==========
  customerConfirmedAt: cp.customer_confirmed_at || null,
  customerConfirmedPosition: cp.customer_confirmed_position
    ? parseFloat(cp.customer_confirmed_position)
    : null,
  providerConfirmedAt: cp.provider_confirmed_at || null,
  providerConfirmedPosition: cp.provider_confirmed_position
    ? parseFloat(cp.provider_confirmed_position)
    : null,
  agreementReachedAt: cp.agreement_reached_at || null,
  finalAgreedPosition: cp.final_agreed_position
    ? parseFloat(cp.final_agreed_position)
    : null,

  // Helper flags for frontend
  isAgreed: cp.status === "agreed",
  isCustomerConfirmed:
    cp.status === "customer_confirmed" || cp.status === "agreed",
  isProviderConfirmed:
    cp.status === "provider_confirmed" || cp.status === "agreed",

  // ========== Locking Fields ==========
  isLocked: cp.is_locked || false,
  lockedAt: cp.locked_at || null,
  lockedByUserId: cp.locked_by_user_id || null,
}));

// Log clause stats
console.log("=== CLAUSE STATS ===");
console.log("Total clauses mapped:", clauses.length);
if (clauses.length > 0) {
  console.log("First clause check:", {
    positionId: clauses[0].positionId,
    clauseId: clauses[0].clauseId,
    clauseName: clauses[0].clauseName,
    category: clauses[0].category,
  });
}

const templateClauses = clauses.filter(
  (c) => c.sourceType === "template",
).length;
const legacyClauses = clauses.filter((c) => c.sourceType === "legacy").length;
const customClauses = clauses.filter((c) => c.sourceType === "custom").length;
const clausesWithOptions = clauses.filter(
  (c) => c.positionOptions !== null,
).length;
const agreedClauses = clauses.filter((c) => c.isAgreed).length;
const pendingConfirmation = clauses.filter(
  (c) => c.isCustomerConfirmed !== c.isProviderConfirmed,
).length;

console.log(
  "Clause sources - Template:",
  templateClauses,
  "Legacy:",
  legacyClauses,
  "Custom:",
  customClauses,
);
console.log("Clauses with position options:", clausesWithOptions);
console.log(
  "Agreed clauses:",
  agreedClauses,
  "Pending confirmation:",
  pendingConfirmation,
);

// ============================================================================
// SECTION 5: BUILD LEVERAGE RESPONSE
// ============================================================================

const leverage = {
  // Master leverage scores (BASELINE - NEVER CHANGES)
  leverageScoreCustomer: baselineCustomerLeverage,
  leverageScoreProvider: baselineProviderLeverage,
  leverageScoreCalculatedAt:
    leverageData.calculated_at || sessionData.leverage_calculated_at || null,

  // Dynamic tracker (changes with position moves)
  leverageTrackerCustomer: trackerCustomerLeverage,
  leverageTrackerProvider: trackerProviderLeverage,
  leverageTrackerCalculatedAt:
    leverageData.tracker_calculated_at ||
    sessionData.leverage_tracker_calculated_at ||
    null,

  // Alignment
  alignmentPercentage: alignmentPercentage,
  isAligned: isAligned,

  // Factor breakdowns
  marketDynamicsScore:
    leverageFactors.marketDynamics?.score || baselineCustomerLeverage,
  marketDynamicsRationale:
    leverageFactors.marketDynamics?.rationale || "Not calculated",
  economicFactorsScore:
    leverageFactors.economicFactors?.score || baselineCustomerLeverage,
  economicFactorsRationale:
    leverageFactors.economicFactors?.rationale || "Not calculated",
  strategicPositionScore:
    leverageFactors.strategicPosition?.score || baselineCustomerLeverage,
  strategicPositionRationale:
    leverageFactors.strategicPosition?.rationale || "Not calculated",
  batnaScore: leverageFactors.batna?.score || baselineCustomerLeverage,
  batnaRationale: leverageFactors.batna?.rationale || "Not calculated",

  // Status flag
  isPending: !hasLeverageCalculation,
};

// ============================================================================
// SECTION 6: BUILD UNSEEN MOVES RESPONSE
// ============================================================================

const unseenMoves = unseenMovesData.map((item) => ({
  clauseId: item.clause_id,
  unseenCount: parseInt(item.unseen_count) || 0,
}));

const totalUnseenMoves = unseenMoves.reduce(
  (sum, item) => sum + item.unseenCount,
  0,
);

console.log("Unseen moves:", unseenMoves.length);
console.log("Total unseen:", totalUnseenMoves);

// ============================================================================
// SECTION 7: FINAL RESPONSE
// ============================================================================

console.log("=== RESPONSE V10 BUILT ===");
console.log("Session mediationType:", session.mediationType);
console.log("Session templateSource:", session.templateSource);
console.log("Clauses:", clauses.length);
console.log(
  "Leverage - Baseline:",
  leverage.leverageScoreCustomer,
  "/",
  leverage.leverageScoreProvider,
);
console.log(
  "Leverage - Tracker:",
  leverage.leverageTrackerCustomer,
  "/",
  leverage.leverageTrackerProvider,
);
console.log("Viewer role:", session.viewer.role);

return [
  {
    json: {
      session,
      clauses,
      leverage,
      unseenMoves,
      totalUnseenMoves,
    },
  },
];
